package hqc

import (
	"crypto/sha3"
	"encoding/hex"
	"encoding/json"
	"os"
	"strconv"
	"testing"
)

// TestAccumulated verifies the Go implementation against accumulated hash
// anchors generated by v5.0.0 C. Each iteration:
//  1. Squeeze 48 bytes from SHAKE128 source -> keygen entropy
//  2. Init HQC KAT RNG (SHAKE256(entropy || 0x01)) -> keygen reads from it
//  3. Absorb pk, sk into accumulator
//  4. Squeeze 48 bytes from SHAKE128 source -> encaps entropy
//  5. Init HQC KAT RNG again -> encaps reads from it
//  6. Absorb ct, ss_enc into accumulator
//  7. Decaps(ct, sk) -> absorb ss_dec
//
// Final accumulator squeeze(32) must match the reference hash.
//
// Tiers controlled by GOHQC_ACCUMULATED env var:
//
//	unset or "100"  -> 100 iterations (<1s, default)
//	"1000"          -> 1,000 iterations (~3s)
//	"10000"         -> 10,000 iterations (~30s)
//	"100000"        -> 100,000 iterations (~5 min, pre-release gate)
//
// The 1M tier is reference-only and not executed by Go tests.
func TestAccumulated128(t *testing.T) {
	runAccumulated(t, "hqc-128",
		func(rng *KATRNG) (pk, sk []byte, err error) {
			dk, err := GenerateKeyForTest128(rng)
			if err != nil {
				return nil, nil, err
			}
			return dk.EncapsulationKey().Bytes(), dk.Bytes(), nil
		},
		func(rng *KATRNG, pk []byte) (ct, ssEnc []byte, err error) {
			ek, err := ParseEncapsulationKey128(pk)
			if err != nil {
				return nil, nil, err
			}
			ssEnc, ct = EncapsulateForTest128(ek, rng)
			return ct, ssEnc, nil
		},
		func(sk, ct []byte) (ssDec []byte, err error) {
			dk, err := ParseDecapsulationKey128(sk)
			if err != nil {
				return nil, err
			}
			ssDec, err = dk.Decapsulate(ct)
			dk.Destroy()
			return ssDec, err
		},
	)
}

