type accumulatedFile struct {
	HQC128 accumulatedParamSet `json:"hqc-128"`
	HQC192 accumulatedParamSet `json:"hqc-192"`
	HQC256 accumulatedParamSet `json:"hqc-256"`
}

type accumulatedParamSet struct {
	Hashes map[string]string `json:"hashes"`
}

func runAccumulated(t *testing.T, name string,
	keygen func(*KATRNG) (pk, sk []byte, err error),
	encaps func(*KATRNG, []byte) (ct, ssEnc []byte, err error),
	decaps func(sk, ct []byte) (ssDec []byte, err error),
) {
	t.Helper()

	tier := 100
	if env := os.Getenv("GOHQC_ACCUMULATED"); env != "" {
		n, err := strconv.Atoi(env)
		if err != nil {
			t.Fatalf("GOHQC_ACCUMULATED=%q: %v", env, err)
		}
		tier = n
	}

	// Load reference hashes.
	var af accumulatedFile
	data, err := os.ReadFile("testdata/accumulated.json")
	if err != nil {
		t.Fatalf("read accumulated.json: %v", err)
	}
	if err := json.Unmarshal(data, &af); err != nil {
		t.Fatalf("parse accumulated.json: %v", err)
	}

	var hashes map[string]string
	switch name {
	case "hqc-128":
		hashes = af.HQC128.Hashes
	case "hqc-192":
		hashes = af.HQC192.Hashes
	case "hqc-256":
		hashes = af.HQC256.Hashes
	}

	tierStr := strconv.Itoa(tier)
	wantHex, ok := hashes[tierStr]
	if !ok {
		t.Fatalf("no reference hash for tier %d in %s", tier, name)
	}

	// SHAKE128 entropy source (empty init, finalized, deterministic).
	source := sha3.NewSHAKE128()

	// SHAKE128 accumulator (absorbs all outputs).
	accum := sha3.NewSHAKE128()

	entropy := make([]byte, 48)

	for i := 0; i < tier; i++ {
		// Step 1: squeeze 48 bytes from source -> keygen entropy.
		source.Read(entropy)

		// Step 2: create HQC KAT RNG from entropy, keygen via it.
		keyRNG := NewKATRNG(entropy)
		pk, sk, err := keygen(keyRNG)
		if err != nil {
			t.Fatalf("iter %d: keygen: %v", i, err)
		}

		// Step 3: absorb pk, sk.
		accum.Write(pk)
		accum.Write(sk)

		// Step 4: squeeze 48 bytes from source -> encaps entropy.
		source.Read(entropy)

		// Step 5: create new KAT RNG, encaps via it.
		encRNG := NewKATRNG(entropy)
		ct, ssEnc, err := encaps(encRNG, pk)
		if err != nil {
			t.Fatalf("iter %d: encaps: %v", i, err)
		}

		// Step 6: absorb ct, ss_enc.
		accum.Write(ct)
		accum.Write(ssEnc)

		// Step 7: decaps (no randomness needed).
		ssDec, err := decaps(sk, ct)
		if err != nil {
			t.Fatalf("iter %d: decaps: %v", i, err)
		}

		// Step 8: absorb ss_dec.
		accum.Write(ssDec)
	}

	// Final squeeze: 32 bytes.
	got := make([]byte, 32)
	accum.Read(got)

	gotHex := hex.EncodeToString(got)
	if gotHex != wantHex {
		t.Fatalf("%s tier %d: accumulated hash mismatch\ngot:  %s\nwant: %s",
			name, tier, gotHex, wantHex)
	}

	t.Logf("%s tier %d: PASS (%s)", name, tier, gotHex[:16]+"...")
}
